INSERT INTO `power` VALUES (1,'BR','DICE','Pak 1 [soort voedsel] uit het vogelhuisje, indien beschikbaar.'),(2,'WH','DICE','Pak alle [soort voedsel] die in het vogelhuisje liggen.'),(3,'BR','DICE','Iedere speler pakt 1 [voedsel] uit het vogelhuisje, te beginnen bij een speler van jouw keuze.'),(4,'BR','DICE','De speler(s) met de minste vogels in zijn/hun [bos] pakt/pakken 1 [dobbelsteen] uit het vogelhuisje.'),(5,'PK','DICE','Als een [jaagactie] van een andere speler lukt, pak jij 1 [dobbelsteen] ut het vogelhuisje.'),(6,'BR','FOOD','Pak 1 [specifieke voedselsoort] uit de voorraad.'),(7,'WH','FOOD','Pak 3 [specifieke voedselsoort] uit de voorraad.'),(8,'BR','FOOD','Ruil 1 voedselfiche naar keuze tegen 1 ander type uit de voorraad.'),(9,'BR','FOOD','Leg 1 [ei] van één van je andere vogels af om [1/2] voedsel uit de voorraad te pakken.'),(10,'PK','FOOD','Als een andere speler een vogel in zijn [specifieke leefomgeving] speelt, pak jij 1 [specifieke voedselsoort] uit de voorraad.'),(11,'BR','FOOD','Alle spelers pakken 1 [specifieke voedselsoort] uit de voorraad.'),(12,'BR','CACH','Pak 1 [graan] uit de voorraad en bewaar die op deze vogel.'),(13,'PK','CACH','Als een andere speler de actie \'Voedsel pakken\' uitvoert en tenminste 1 [rat] pakt, dan pak jij ook 1 [rat] en bewaar je die op deze vogel.'),(14,'BR','CACH','Pak 1 [graan] uit het vogelhuisje, indien beschikbaar. Je mag die op deze vogel bewaren.'),(15,'PK','EGGS','Als een andere speler de acie \'Eieren leggen\' uitvoert, legt deze vogel 1 [ei] op een andere vogel met een [specifieke nestsoort]-nest.'),(16,'WH','EGGS','Leg 1 [ei] op elk van je vogels met een [specifieke nestsoort]-nest.'),(17,'BR','EGGS','Alle spelers leggen 1 [ei] op 1 vogel naar keuze [met een specifieke nestsoort]. Jij mag daarnaast nog 1 [ei] op 1 andere vogel [met dezelfde nestsoort] leggen.'),(18,'BR','EGGS','Leg 1 [ei] op een vogel naar keuze.'),(19,'BR','EGGS','Leg 1 [ei] op deze vogel.'),(20,'BR','CARD','Trek 1 [kaart].'),(21,'WH','CARD','Trek 2 [kaart].'),(22,'BR','CARD','Trek 1 [kaart]. Doe je dat, leg dan aan het einde van je beurt 1 [kaart] uit je hand af.'),(23,'BR','CARD','Trek 2 [kaart]. Doe je dat, leg dan aan het einde van je beurt 1 [kaart] uit je hand af.'),(24,'BR','CARD','Leg 1 [ei] af om 2 [kaart] te trekken.'),(25,'BR','CARD','Alle spelers trekken 1 [kaart] van de gedekte stapel.'),(26,'BR','CARD','De speler(s) met de minste vogels in zijn/hun [moeras]: trek 1 [kaart].'),(27,'WH','CARD','Trek zoveel [kaart] als het aantal spelers + 1. Te beginnnen bij jou en daarna met de klok mee, kiest iedere speler 1 van deze kaarten en doet die in zijn hand. Jij houdt de overgebleven kaart.'),(28,'WH','CARD','Trek de 3 open [kaart] uit de vogelhouder.'),(29,'PK','SWRM','Als een andere speler een vogel in zijn [weide] speelt, stop jij 1 [kaart] uit je hand weg onder deze vogel.'),(30,'BR','SWRM','Stop 1 [kaart] uit je hand onder deze vogel weg. Doe je dat, dan mag je ook 1 [ei] op deze vogel leggen.'),(31,'BR','SWRM','Stop 1 [kaart] uit je hand onder deze vogel weg. Doe je dat, trek dan 1 [kaart].'),(32,'BR','SWRM','Stop 1 [kaart] uit je hand onder deze vogel weg. Doe je dat, pak dan 1 [specifieke voedselsoort] uit de voorraad.'),(33,'BR','SWRM','Leg 1 [specifieke voedselsoort] af om 2 [kaart] van de gedekte stapel onder deze vogel weg te stoppen.'),(34,'BR','SWRM','Stop 1 [kaart] uit je hand onder deze vogel weg. Doe je dat, leg dan 1 [ei] op een vogel naar keuze.'),(35,'BR','HUNT','Bekijk een [kaart] van de gedekte stapel. Is die < [bepaalde vleugelwijdte], stop hem dan weg onder deze vogel.'),(36,'BR','HUNT','Werp alle dobbelstenen die in het vogelhuisje liggen. Gooi je tenminste 1 [vis/rat], pak dan 1 [vis/rat] en bewaar die op deze vogel.'),(37,'BR',NULL,'Als deze vogel zich rechts van alle andere vogels in zijn leefomgeving bevindt, verplaats deze dan naar een andere leefomgeving.'),(38,'BR',NULL,'Herhaal een bruine eigenschap van een andere vogel in deze leefomgeving.'),(39,'BR',NULL,'Herhaal een [jaag]-eigenschap in deze leefomgeving.'),(40,'WH',NULL,'Trek 2 bonuskaarten en houd er 1.'),(41,'WH',NULL,'Speel een extra vogel in je [specifieke leefomgeving]. Betaal de normale kosten ervan.');
